    public static function init(){
        add_action('init',[__CLASS__,'register_pages'],30);
        add_action('admin_menu',[__CLASS__,'admin_menu'],99);
        add_action('admin_post_tager_v54_repair',[__CLASS__,'repair']);
        add_action('admin_post_tager_v54_save_customer',[__CLASS__,'save_customer']);
        add_action('admin_post_tager_v54_save_vendor',[__CLASS__,'save_vendor']);
        add_action('admin_post_tager_v54_save_product',[__CLASS__,'save_product']);
        foreach([
            'customer_home','customer_profile','customer_orders','customer_addresses','customer_payments','customer_security',
            'vendor_home','vendor_products','vendor_product_form','vendor_orders','vendor_inventory','vendor_finance','vendor_settings',
            'admin_home','admin_vendors','admin_products','admin_orders','admin_finance','page_status'
        ] as $sc){ add_shortcode('tager_v54_'.$sc,[__CLASS__,$sc]); }
        add_filter('the_content',[__CLASS__,'human_context_bar'],120);
        add_action('wp_footer',[__CLASS__,'frontend_qa']);
    }

    private static function url($slug,$args=[]){
        $p=get_page_by_path($slug); $u=$p?get_permalink($p):home_url('/'.trim($slug,'/').'/');
        return $args?add_query_arg($args,$u):$u;
    }
    private static function roles(){ return is_user_logged_in()?(array)wp_get_current_user()->roles:[]; }
    private static function is_vendor(){ return (bool)array_intersect(self::roles(),['tager_vendor','wcfm_vendor','vendor']); }
    private static function is_admin_team(){ return current_user_can('manage_options') || (bool)array_intersect(self::roles(),['tager_admin','tager_ops_manager','tager_vendor_manager','tager_catalog_manager','tager_orders_manager','tager_finance','tager_support','tager_marketing','tager_viewer']); }
    private static function need_login(){ return self::empty_state('لازم تسجل الدخول أولًا حتى نعرض بيانات حسابك الحقيقية.',self::url('login'),'تسجيل الدخول'); }
    private static function deny($role){ return self::empty_state('الصفحة دي مخصصة لـ '.$role.' فقط.',home_url('/'),'العودة للرئيسية'); }

    public static function register_pages(){
        foreach(self::$pages as $slug=>$def){
            $p=get_page_by_path($slug);
            if(!$p){ wp_insert_post(['post_type'=>'page','post_status'=>'publish','post_title'=>$def[0],'post_name'=>$slug,'post_content'=>$def[1]]); }
            elseif(trim((string)$p->post_content)==='' || strpos((string)$p->post_content,'tager_v54_')===false){ wp_update_post(['ID'=>$p->ID,'post_content'=>$def[1]]); }
        }
    }

    private static function style(){ static $x=false; if($x)return ''; $x=true; return '<style>
    .tv54{max-width:1220px;margin:24px auto;padding:20px}.tv54 h1,.tv54 h2,.tv54 h3{color:#173d2d}.tv54-head{display:flex;justify-content:space-between;gap:18px;align-items:center;margin-bottom:20px}.tv54-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:15px}.tv54-card,.tv54-panel,.tv54-empty,.tv54-form{background:#fff;border:1px solid #e7e1d5;border-radius:18px;padding:18px;box-shadow:0 8px 25px rgba(23,61,45,.06)}.tv54-card strong{display:block;font-size:25px;color:#173d2d;margin:8px 0}.tv54-muted{color:#667085}.tv54-btn{display:inline-flex;align-items:center;justify-content:center;gap:7px;background:#173d2d;color:#fff!important;border:0;border-radius:11px;padding:11px 16px;text-decoration:none;font-weight:700;cursor:pointer}.tv54-btn.gold{background:#b99342}.tv54-btn.light{background:#eef4f0;color:#173d2d!important}.tv54-actions{display:flex;flex-wrap:wrap;gap:10px}.tv54-table{width:100%;border-collapse:collapse}.tv54-table th,.tv54-table td{padding:12px;border-bottom:1px solid #eee;text-align:right;vertical-align:top}.tv54-form label{display:block;font-weight:700;margin:12px 0 5px}.tv54-form input,.tv54-form select,.tv54-form textarea{width:100%;border:1px solid #d8d5cc;border-radius:10px;padding:11px}.tv54-form textarea{min-height:110px}.tv54-status{display:inline-block;padding:5px 9px;border-radius:999px;background:#eef4f0;color:#173d2d;font-size:12px;font-weight:700}.tv54-warn{background:#fff4df;color:#8a5a00}.tv54-bad{background:#ffe9e9;color:#a11}.tv54-checklist{list-style:none;padding:0;margin:0}.tv54-checklist li{padding:10px 0;border-bottom:1px solid #eee}.tv54-progress{height:10px;background:#eee;border-radius:99px;overflow:hidden}.tv54-progress span{display:block;height:100%;background:#b99342}.tv54-empty{text-align:center;padding:36px}.tv54-human-note{padding:13px 15px;border-right:4px solid #b99342;background:#fff8e8;border-radius:10px;margin:12px 0}.tv54-context{max-width:1220px;margin:14px auto;padding:0 20px}.tv54-context-inner{display:flex;justify-content:space-between;gap:10px;align-items:center;background:#173d2d;color:#fff;border-radius:14px;padding:11px 14px}.tv54-context a{color:#fff;text-decoration:none;font-weight:700}.tv54-missing{border-color:#efb1b1;background:#fffafa}.tv54-complete{border-color:#b8dec5;background:#fbfffc}@media(max-width:720px){.tv54{padding:12px}.tv54-head{align-items:flex-start;flex-direction:column}.tv54-actions,.tv54-btn{width:100%}.tv54-context-inner{align-items:flex-start;flex-direction:column}.tv54-table{display:block;overflow:auto}}
    </style>'; }
    private static function card($label,$value,$note='',$url='',$button='فتح'){ return '<div class="tv54-card"><div class="tv54-muted">'.esc_html($label).'</div><strong>'.esc_html($value).'</strong>'.($note?'<p class="tv54-muted">'.esc_html($note).'</p>':'').($url?'<a class="tv54-btn light" href="'.esc_url($url).'">'.esc_html($button).'</a>':'').'</div>'; }
    private static function empty_state($text,$url,$label){ return self::style().'<div class="tv54 tv54-empty"><h2>لا توجد بيانات بعد</h2><p>'.esc_html($text).'</p><a class="tv54-btn" href="'.esc_url($url).'">'.esc_html($label).'</a></div>'; }
    private static function completeness($fields){ $ok=0; foreach($fields as $v){ if(trim((string)$v)!=='')$ok++; } return count($fields)?(int)round($ok/count($fields)*100):0; }

    public static function customer_home(){
        if(!is_user_logged_in())return self::need_login(); if(self::is_vendor()||self::is_admin_team())return self::deny('العميل');
        $uid=get_current_user_id(); $orders=get_posts(['post_type'=>'tager_order','author'=>$uid,'post_status'=>'any','posts_per_page'=>-1]);
        $total=0;$active=0;foreach($orders as $o){$total+=(float)get_post_meta($o->ID,'total',true);$s=(string)get_post_meta($o->ID,'status',true);if(!in_array($s,['completed','cancelled'],true))$active++;}
        $fields=[get_user_meta($uid,'first_name',true),get_user_meta($uid,'tager_phone',true),get_user_meta($uid,'tager_governorate',true),get_user_meta($uid,'tager_city',true),get_user_meta($uid,'tager_address',true)];
        $c=self::completeness($fields);
        $h=self::style().'<section class="tv54"><div class="tv54-head"><div><h1>أهلًا '.esc_html(wp_get_current_user()->display_name).'</h1><p class="tv54-muted">دي الصفحة اللي العميل يتوقع يشوف فيها كل حاجة مهمة فورًا.</p></div><div class="tv54-actions"><a class="tv54-btn gold" href="'.esc_url(self::url('products')).'">تسوق الآن</a><a class="tv54-btn light" href="'.esc_url(self::url('customer-profile')).'">تعديل الحساب</a></div></div>';
        $h.='<div class="tv54-grid">'.self::card('اكتمال الحساب',$c.'%','كلما اكتملت البيانات كان الطلب أسرع',self::url('customer-profile'),'استكمال').self::card('كل الطلبات',count($orders),'',self::url('customer-orders')).self::card('طلبات نشطة',$active,'').self::card('إجمالي المشتريات',number_format_i18n($total,2).' ج.م').'</div>';
        if($c<100)$h.='<div class="tv54-human-note"><strong>كمستخدم:</strong> ينقص حسابك بعض البيانات التي يحتاجها الشحن والفاتورة. افتح الملف الشخصي وأكمل المحافظة والمركز والعنوان.</div>';
        $h.='<div class="tv54-grid"><a class="tv54-card" href="'.esc_url(self::url('customer-orders')).'"><h3>طلباتي</h3><p>تابع الحالة والدفع والشحن.</p></a><a class="tv54-card" href="'.esc_url(self::url('customer-addresses')).'"><h3>العناوين</h3><p>احفظ أكثر من عنوان وحدد الافتراضي.</p></a><a class="tv54-card" href="'.esc_url(self::url('customer-payments')).'"><h3>وسائل الدفع</h3><p>اعرف طرق الدفع المتاحة وتعليماتها.</p></a><a class="tv54-card" href="'.esc_url(self::url('customer-security')).'"><h3>أمان الحساب</h3><p>غيّر كلمة المرور وراجع الهاتف والبريد.</p></a></div></section>'; return $h;
    }

    public static function customer_profile(){
        if(!is_user_logged_in())return self::need_login(); if(self::is_vendor()||self::is_admin_team())return self::deny('العميل');
        $uid=get_current_user_id();$u=get_userdata($uid);
        $meta=['first_name'=>get_user_meta($uid,'first_name',true),'tager_phone'=>get_user_meta($uid,'tager_phone',true),'tager_governorate'=>get_user_meta($uid,'tager_governorate',true),'tager_city'=>get_user_meta($uid,'tager_city',true),'tager_address'=>get_user_meta($uid,'tager_address',true)];
        $h=self::style().'<section class="tv54"><div class="tv54-head"><div><h1>الملف الشخصي</h1><p class="tv54-muted">الهاتف أساسي، والبريد اختياري.</p></div><a class="tv54-btn light" href="'.esc_url(self::url('customer-home')).'">مركز العميل</a></div><form class="tv54-form" method="post" action="'.esc_url(admin_url('admin-post.php')).'">';
        $h.=wp_nonce_field('tager_v54_save_customer',self::NONCE,true,false).'<input type="hidden" name="action" value="tager_v54_save_customer">';
        $h.='<div class="tv54-grid"><div><label>الاسم الكامل *</label><input required name="first_name" value="'.esc_attr($meta['first_name']).'"></div><div><label>رقم الهاتف *</label><input required name="phone" inputmode="tel" value="'.esc_attr($meta['tager_phone']).'"></div><div><label>البريد الإلكتروني (اختياري)</label><input type="email" name="email" value="'.esc_attr($u?$u->user_email:'').'"></div><div><label>المحافظة *</label><input required name="governorate" value="'.esc_attr($meta['tager_governorate']).'"></div><div><label>المركز / المدينة *</label><input required name="city" value="'.esc_attr($meta['tager_city']).'"></div><div><label>العنوان بالتفصيل *</label><input required name="address" value="'.esc_attr($meta['tager_address']).'"></div></div><div class="tv54-actions"><button class="tv54-btn" type="submit">حفظ كل البيانات</button><a class="tv54-btn light" href="'.esc_url(self::url('customer-security')).'">إعدادات الأمان</a></div></form></section>';return $h;
    }
    public static function customer_orders(){
        if(!is_user_logged_in())return self::need_login(); if(self::is_vendor()||self::is_admin_team())return self::deny('العميل');
        $orders=get_posts(['post_type'=>'tager_order','author'=>get_current_user_id(),'post_status'=>'any','posts_per_page'=>50]);
        if(!$orders)return self::empty_state('لسه ماعملتش طلب. افتح السوق واختر المنتجات المناسبة.',self::url('products'),'ابدأ التسوق');
        $h=self::style().'<section class="tv54"><div class="tv54-head"><div><h1>طلباتي</h1><p class="tv54-muted">رقم الطلب، الحالة، الدفع، الشحن، والإجمالي في مكان واحد.</p></div><a class="tv54-btn gold" href="'.esc_url(self::url('products')).'">طلب جديد</a></div><div class="tv54-panel"><table class="tv54-table"><thead><tr><th>الطلب</th><th>التاريخ</th><th>الحالة</th><th>الدفع</th><th>الإجمالي</th><th>تفاصيل</th></tr></thead><tbody>';
        foreach($orders as $o){$h.='<tr><td>#'.intval($o->ID).'</td><td>'.esc_html(get_the_date('Y-m-d',$o)).'</td><td><span class="tv54-status">'.esc_html(get_post_meta($o->ID,'status',true)?:'new').'</span></td><td>'.esc_html(get_post_meta($o->ID,'payment_method',true)?:'غير محدد').'</td><td>'.esc_html(get_post_meta($o->ID,'total',true)?:0).' ج.م</td><td><a class="tv54-btn light" href="'.esc_url(self::url('order-details',['order_id'=>$o->ID])).'">فتح</a></td></tr>';}
        return $h.'</tbody></table></div></section>';
    }
    public static function customer_addresses(){ if(!is_user_logged_in())return self::need_login(); return self::customer_profile(); }
    public static function customer_payments(){ return self::style().'<section class="tv54"><h1>وسائل الدفع</h1><div class="tv54-grid">'.self::card('الدفع عند الاستلام','متاح حسب قيمة الطلب','قد تُطبق رسوم').self::card('تحويل بنكي','متاح','يحتاج رقم مرجعي').self::card('InstaPay / محفظة','متاح حسب إعداد الإدارة','يمكن رفع إثبات').self::card('بطاقة / فوري','جاهز للربط','يحتاج بوابة دفع فعلية').'</div><div class="tv54-human-note">كمستخدم لازم أعرف قبل الطلب: هل الطريقة متاحة؟ رسومها كام؟ وإزاي أثبت الدفع؟ الصفحة تعرض ده بوضوح.</div></section>'; }
    public static function customer_security(){ if(!is_user_logged_in())return self::need_login(); $u=wp_get_current_user(); return self::style().'<section class="tv54"><h1>أمان الحساب</h1><div class="tv54-grid">'.self::card('الهاتف',get_user_meta($u->ID,'tager_phone',true)?:'غير مكتمل','أساسي للدخول والاستعادة').self::card('البريد',$u->user_email?:'اختياري وغير مضاف','يمكن استخدامه لاستعادة كلمة المرور').self::card('نسيت كلمة المرور','متاح','بالهاتف أو البريد',self::url('forgot-password'),'فتح الاستعادة').'</div></section>'; }

    public static function vendor_home(){
        if(!is_user_logged_in())return self::need_login(); if(!self::is_vendor()&&!self::is_admin_team())return self::deny('المورد');
        $uid=get_current_user_id();$products=get_posts(['post_type'=>'tager_product','author'=>$uid,'post_status'=>'any','posts_per_page'=>-1]);$pub=0;$pending=0;$low=0;foreach($products as $p){$p->post_status==='publish'?$pub++:$pending++;if((float)get_post_meta($p->ID,'stock',true)<=5)$low++;}
        $fields=[get_user_meta($uid,'tager_store_name',true),get_user_meta($uid,'tager_phone',true),get_user_meta($uid,'tager_governorate',true),get_user_meta($uid,'tager_city',true),get_user_meta($uid,'tager_vendor_min_order',true),get_user_meta($uid,'tager_vendor_logo',true)];$c=self::completeness($fields);
        $h=self::style().'<section class="tv54"><div class="tv54-head"><div><h1>لوحة المورد</h1><p class="tv54-muted">المورد يحتاج يعرف فورًا: المتجر جاهز؟ المنتجات منشورة؟ الطلبات وصلت؟ الأرباح كام؟</p></div><div class="tv54-actions"><a class="tv54-btn gold" href="'.esc_url(self::url('vendor-product-form')).'">إضافة منتج</a><a class="tv54-btn light" href="'.esc_url(self::url('vendor-market')).'">مشاهدة السوق</a></div></div><div class="tv54-grid">'.self::card('جاهزية المتجر',$c.'%','',self::url('vendor-store-settings'),'استكمال').self::card('كل المنتجات',count($products),'',self::url('vendor-products')).self::card('منشورة',$pub).self::card('تحت المراجعة',$pending).self::card('مخزون منخفض',$low,'',self::url('vendor-inventory')).'</div>';
        if($c<100)$h.='<div class="tv54-human-note"><strong>كمورد:</strong> قبل ما أبيع، لازم أكمل الشعار، المحافظة، المركز، الهاتف، والحد الأدنى للطلب.</div>';
        return $h.'<div class="tv54-grid"><a class="tv54-card" href="'.esc_url(self::url('vendor-products')).'"><h3>منتجاتي</h3><p>إضافة وتعديل الأسعار والصور والمخزون.</p></a><a class="tv54-card" href="'.esc_url(self::url('vendor-orders')).'"><h3>الطلبات</h3><p>تابع المنتجات المطلوبة وحدّث الحالة.</p></a><a class="tv54-card" href="'.esc_url(self::url('vendor-finance')).'"><h3>الأرباح</h3><p>الإجمالي والعمولة والصافي.</p></a><a class="tv54-card" href="'.esc_url(self::url('vendor-store-settings')).'"><h3>إعدادات المتجر</h3><p>بيانات المتجر ومناطق الخدمة.</p></a></div></section>';
    }
    public static function vendor_products(){
        if(!is_user_logged_in())return self::need_login(); if(!self::is_vendor()&&!self::is_admin_team())return self::deny('المورد');$uid=get_current_user_id();$items=get_posts(['post_type'=>'tager_product','author'=>$uid,'post_status'=>'any','posts_per_page'=>100]);
        if(!$items)return self::empty_state('لسه ما أضفتش منتجات. أضف أول منتج بكامل الأسعار والصور والمخزون.',self::url('vendor-product-form'),'إضافة أول منتج');
        $h=self::style().'<section class="tv54"><div class="tv54-head"><div><h1>منتجاتي</h1><p class="tv54-muted">راجع حالة النشر واكتمال كل منتج.</p></div><a class="tv54-btn gold" href="'.esc_url(self::url('vendor-product-form')).'">إضافة منتج</a></div><div class="tv54-panel"><table class="tv54-table"><thead><tr><th>المنتج</th><th>الحالة</th><th>قطاعي</th><th>جملة</th><th>جملة الجملة</th><th>المخزون</th><th>اكتمال</th><th>تعديل</th></tr></thead><tbody>';
        foreach($items as $p){$vals=[get_post_thumbnail_id($p->ID),get_post_meta($p->ID,'retail_price',true),get_post_meta($p->ID,'wholesale_price',true),get_post_meta($p->ID,'bulk_price',true),get_post_meta($p->ID,'stock',true),$p->post_content];$c=self::completeness($vals);$h.='<tr><td>'.esc_html($p->post_title).'</td><td><span class="tv54-status">'.esc_html($p->post_status).'</span></td><td>'.esc_html(get_post_meta($p->ID,'retail_price',true)?:'—').'</td><td>'.esc_html(get_post_meta($p->ID,'wholesale_price',true)?:'—').'</td><td>'.esc_html(get_post_meta($p->ID,'bulk_price',true)?:'—').'</td><td>'.esc_html(get_post_meta($p->ID,'stock',true)?:0).'</td><td>'.$c.'%</td><td><a class="tv54-btn light" href="'.esc_url(self::url('vendor-product-form',['product_id'=>$p->ID])).'">تعديل</a></td></tr>';}
        return $h.'</tbody></table></div></section>';
    }
    public static function vendor_product_form(){
