        $ret=(float)($_POST['retail_price']??0);$wh=(float)($_POST['wholesale_price']??0);$bulk=(float)($_POST['bulk_price']??0);$wmin=(float)($_POST['wholesale_min']??0);$bmin=(float)($_POST['bulk_min']??0);if($ret<$wh||$wh<$bulk)wp_die('Pricing order invalid');if($bmin<=$wmin)wp_die('Bulk minimum must exceed wholesale minimum');
        $post=['post_type'=>'tager_product','post_status'=>'pending','post_title'=>sanitize_text_field($_POST['title']??''),'post_content'=>wp_kses_post($_POST['description']??''),'post_author'=>$uid];$post['ID']=$id;$id=$id?wp_update_post($post,true):wp_insert_post($post,true);if(is_wp_error($id))wp_die($id->get_error_message());
        foreach(['sku','category','brand','unit','lead_time','retail_price','wholesale_price','bulk_price','wholesale_min','bulk_min','stock','max_order'] as $k)update_post_meta($id,$k,sanitize_text_field($_POST[$k]??''));
        if(!empty($_FILES['main_image']['name'])){require_once ABSPATH.'wp-admin/includes/file.php';require_once ABSPATH.'wp-admin/includes/media.php';require_once ABSPATH.'wp-admin/includes/image.php';$att=media_handle_upload('main_image',$id);if(!is_wp_error($att))set_post_thumbnail($id,$att);} 
        wp_safe_redirect(add_query_arg('saved','1',self::url('vendor-products')));exit;
    }

