    public static function frontend_qa(){ if(is_admin())return; ?><script>(function(){
      function txt(el){return (el.textContent||el.value||'').trim().replace(/\s+/g,' ')}
      document.querySelectorAll('a,button').forEach(function(el){var href=el.getAttribute('href');if(el.tagName==='A'&&(!href||href==='#'||href.indexOf('javascript:')===0)){el.classList.add('tv54-missing');el.setAttribute('aria-disabled','true');el.title='الرابط غير مكتمل';}}
      document.querySelectorAll('form').forEach(function(f){var submits=f.querySelectorAll('button[type=submit],input[type=submit]');if(submits.length>1){for(var i=1;i<submits.length;i++){if(txt(submits[i])===txt(submits[0]))submits[i].remove();}}f.addEventListener('submit',function(e){var bad=f.querySelector(':invalid');if(bad){e.preventDefault();bad.focus();bad.classList.add('tv54-missing');return;}var b=f.querySelector('button[type=submit],input[type=submit]');if(b){b.disabled=true;if(b.tagName==='BUTTON'){b.dataset.old=b.innerHTML;b.innerHTML='جاري الحفظ...';}setTimeout(function(){b.disabled=false;if(b.dataset.old)b.innerHTML=b.dataset.old;},9000);}});});
    })();</script><?php }

    private static function audit_page($p){
        $content=(string)$p->post_content;$issues=[];
        if(trim($content)==='')$issues[]='محتوى فارغ';
        if(preg_match('/href=["\'](?:#|javascript:void\(0\)|)["\']/i',$content))$issues[]='رابط فارغ';
        preg_match_all('/\[([a-zA-Z0-9_-]+)/',$content,$m);foreach(array_unique($m[1]??[]) as $sc)if(!shortcode_exists($sc))$issues[]='Shortcode غير موجود: '.$sc;
        if(strpos($content,'<form')!==false && !preg_match('/type=["\']submit["\']|<button/i',$content))$issues[]='نموذج بلا زر حفظ';
        return $issues;
    }
    public static function admin_menu(){ add_menu_page('Tager V54','Tager V54','manage_options','tager-v54',[__CLASS__,'admin_screen'],'dashicons-search',2); }
    public static function admin_screen(){
        if(!current_user_can('manage_options'))return;$pages=get_pages(['post_status'=>'publish','number'=>0]);$bad=[];$ok=0;foreach($pages as $p){$issues=self::audit_page($p);if($issues)$bad[]=[$p,$issues];else$ok++;}
        echo '<div class="wrap"><h1>Tager V54 — مراجعة بشرية للصفحات والأزرار</h1><p>الفحص هنا يراجع الصفحة بالطريقة التي يراها المستخدم: هل فيها محتوى؟ هل الزر له وجهة؟ هل النموذج يحفظ؟ هل البيانات الأساسية ظاهرة؟</p><p><a class="button button-primary" href="'.esc_url(wp_nonce_url(admin_url('admin-post.php?action=tager_v54_repair'),self::NONCE)).'">إصلاح وإنشاء الصفحات الأساسية</a> <a class="button" target="_blank" href="'.esc_url(self::url('customer-home')).'">تجربة العميل</a> <a class="button" target="_blank" href="'.esc_url(self::url('vendor-home')).'">تجربة المورد</a> <a class="button" target="_blank" href="'.esc_url(self::url('admin-home')).'">تجربة الإدارة</a></p><div style="display:flex;gap:15px"><div class="notice notice-success inline"><p>صفحات سليمة مبدئيًا: <strong>'.$ok.'</strong></p></div><div class="notice notice-warning inline"><p>صفحات تحتاج مراجعة: <strong>'.count($bad).'</strong></p></div></div><table class="widefat striped"><thead><tr><th>الصفحة</th><th>المسار</th><th>الملاحظات</th><th>إجراء</th></tr></thead><tbody>';
        foreach($bad as $row){[$p,$issues]=$row;echo '<tr><td>'.esc_html($p->post_title).'</td><td><code>/'.esc_html($p->post_name).'/</code></td><td>'.esc_html(implode(' — ',$issues)).'</td><td><a target="_blank" href="'.esc_url(get_permalink($p)).'">فتح</a> | <a href="'.esc_url(get_edit_post_link($p->ID)).'">تعديل</a></td></tr>';}
        echo '</tbody></table></div>';
    }
    public static function repair(){ if(!current_user_can('manage_options'))wp_die('No permission');check_admin_referer(self::NONCE);foreach(self::$pages as $slug=>$def){$p=get_page_by_path($slug);if(!$p)wp_insert_post(['post_type'=>'page','post_status'=>'publish','post_title'=>$def[0],'post_name'=>$slug,'post_content'=>$def[1]]);else wp_update_post(['ID'=>$p->ID,'post_content'=>$def[1]]);}flush_rewrite_rules(false);wp_safe_redirect(admin_url('admin.php?page=tager-v54&repaired=1'));exit; }
